create function public.prepare_document_upload(
  p_project_id uuid,
  p_type text,
  p_title text,
  p_client_filename text,
  p_mime_type text,
  p_size_bytes bigint,
  p_description text default null,
  p_visibility_class text default 'shared_project'
)
returns table (
  upload_intent_id uuid,
  bucket text,
  object_path text,
  filename text,
  mime_type text,
  size_bytes bigint
)
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_bucket text;
  v_filename text;
  v_intent_id uuid := gen_random_uuid();
  v_vis text;
begin
  if v_uid is null then
    raise exception 'Authentication required';
  end if;

  if not public.can_write_project_content(p_project_id) then
    raise exception 'Insufficient permissions';
  end if;

  if coalesce(trim(p_type), '') = '' then
    raise exception 'Document type is required';
  end if;

  if coalesce(trim(p_title), '') = '' then
    raise exception 'Document title is required';
  end if;

  v_vis := coalesce(nullif(lower(trim(p_visibility_class)), ''), 'shared_project');
  if v_vis not in ('shared_project', 'internal') then
    raise exception 'Invalid visibility_class';
  end if;

  if v_vis = 'internal' and not public.can_view_internal_documents(p_project_id) then
    raise exception 'Insufficient permissions for internal document visibility';
  end if;

  select c.bucket
    into v_bucket
  from public.storage_bucket_config c
  where c.key = 'documents';

  if v_bucket is null or trim(v_bucket) = '' then
    raise exception 'Document upload bucket is not configured';
  end if;

  v_filename := public.sanitize_uploaded_filename(p_client_filename);

  insert into public.document_upload_intents (
    id,
    project_id,
    type,
    title,
    description,
    bucket,
    object_path,
    filename,
    mime_type,
    size_bytes,
    created_by,
    visibility_class
  )
  values (
    v_intent_id,
    p_project_id,
    trim(p_type),
    trim(p_title),
    nullif(trim(p_description), ''),
    v_bucket,
    format('projects/%s/documents/%s/%s', p_project_id, v_intent_id, v_filename),
    v_filename,
    nullif(trim(p_mime_type), ''),
    p_size_bytes,
    v_uid,
    v_vis
  );

  return query
  select
    v_intent_id,
    v_bucket,
    format('projects/%s/documents/%s/%s', p_project_id, v_intent_id, v_filename),
    v_filename,
    nullif(trim(p_mime_type), ''),
    p_size_bytes;
end;
$$;

